package com.hospital.management.validation;import com.hospital.management.model.*;import java.time.*;/** Validates admission lifecycle forms without logging clinical text. */public class AdmissionValidator{public ValidationResult validate(AdmissionForm f){ValidationResult v=new ValidationResult();if(f==null){v.addError("form","Admission is required");return v;}id(f.getPatientId(),"patientId",v);id(f.getDoctorId(),"doctorId",v);id(f.getDepartmentId(),"departmentId",v);id(f.getBedId(),"bedId",v);if(f.getAppointmentId()!=null&&f.getAppointmentId()<=0)v.addError("appointmentId","Invalid appointment");if(f.getExpectedDischargeDate()!=null&&!f.getExpectedDischargeDate().isBlank())try{if(LocalDate.parse(f.getExpectedDischargeDate()).isBefore(LocalDate.now()))v.addError("expectedDischargeDate","Date cannot be in the past");}catch(Exception e){v.addError("expectedDischargeDate","Use yyyy-MM-dd");}text(f.getAdmissionReason(),3,1000,"admissionReason",v);return v;}public ValidationResult validateTransfer(AdmissionTransferForm f){ValidationResult v=new ValidationResult();if(f==null){v.addError("form","Transfer is required");return v;}id(f.getAdmissionId(),"admissionId",v);id(f.getTargetBedId(),"targetBedId",v);text(f.getTransferReason(),3,500,"transferReason",v);return v;}public ValidationResult validateDischarge(DischargeForm f){ValidationResult v=new ValidationResult();if(f==null){v.addError("form","Discharge is required");return v;}id(f.getAdmissionId(),"admissionId",v);text(f.getDischargeSummary(),3,4000,"dischargeSummary",v);return v;}private void id(Long x,String f,ValidationResult v){if(x==null||x<=0)v.addError(f,"A valid value is required");}private void text(String x,int min,int max,String f,ValidationResult v){int n=x==null?0:x.trim().length();if(n<min||n>max)v.addError(f,"Must be "+min+" to "+max+" characters");}}
